    elif type(layer2.data) == ip6.IP6:
        layer3 = layer2.data
        if layer3.nxt == ip.IP_PROTO_TCP:
            dst_port, src_port = parseTcp(layer3.data)
        elif layer3.nxt == ip.IP_PROTO_UDP:
            dst_port, src_port = parseUdp(layer3.data)
        else:
            unknownLayer4.add(layer3.nxt)
    elif type(layer2.data) == arp.ARP:
        layer3 = layer2.data
        nb_arp +=1
